class ImagesController < ApplicationController
  require "fileutils"
  require "securerandom"

  def create
    uploaded_file = params[:image]
    format = params[:format].to_s.strip.downcase
    size = params[:size].to_s.strip

    unless uploaded_file.respond_to?(:path) && format.present?
      render json: { error: "Invalid parameters" }, status: :unprocessable_entity
      return
    end

    allowed_formats = %w[jpg jpeg png gif webp bmp tiff]
    unless allowed_formats.include?(format)
      render json: { error: "Unsupported format" }, status: :unprocessable_entity
      return
    end

    unless size.match?(/\A\d+x\d+\z/)
      render json: { error: "Invalid size" }, status: :unprocessable_entity
      return
    end

    input_path = uploaded_file.path
    output_dir = Rails.root.join("tmp", "processed_images")
    FileUtils.mkdir_p(output_dir)

    output_filename = "#{SecureRandom.uuid}.#{format}"
    output_path = output_dir.join(output_filename)

    cmd = "convert #{Shellwords.escape(input_path)} -resize #{Shellwords.escape(size)} #{Shellwords.escape(output_path.to_s)}"
    success = system(cmd)

    if success && File.exist?(output_path)
      send_file output_path, type: mime_type_for(format), disposition: "inline"
    else
      render json: { error: "Image processing failed" }, status: :internal_server_error
    end
  end

  private

  def mime_type_for(format)
    case format
    when "jpg", "jpeg"
      "image/jpeg"
    when "png"
      "image/png"
    when "gif"
      "image/gif"
    when "webp"
      "image/webp"
    when "bmp"
      "image/bmp"
    when "tiff"
      "image/tiff"
    else
      "application/octet-stream"
    end
